data.solution:
convert = input()
temperature = float(input())
if convert == 'Celsius to Fahrenheit':
    temperature = temperature * 1.8 + 32
    print(f"{temperature:.2f}°F")
if convert == 'Fahrenheit to Celsius':
    temperature = (temperature - 32) * 5/9
    print(f"{temperature:.2f}°C")
if convert == 'Celsius to Kelvin':
    temperature = temperature + 273.15
    print(f"{temperature:.2f}°K")
if convert == 'Kelvin to Celsius':
    temperature = temperature - 273.15
    print(f"{temperature:.2f}°C")
if convert == 'Fahrenheit to Kelvin':
    temperature = (temperature - 32) * 5/9 + 273.15
    print(f"{temperature:.2f}°K")
if convert == 'Kelvin to Fahrenheit':
    temperature = (temperature - 273.15) * 1.8 + 32
    print(f"{temperature:.2f}°F")
